export const meta = {
  name: 'fixture-mini',
  description: 'Tiny fixture workflow for BB capture',
  phases: [
    { title: 'Scan', detail: 'two parallel trivial agents' },
    { title: 'Summarize', detail: 'one summarizing agent' },
  ],
}
phase('Scan')
const words = await parallel([
  () => agent("Reply with exactly the word alpha. Do not use any tools.", {label: 'alpha', model: 'haiku', phase: 'Scan'}),
  () => agent("Reply with exactly the word bravo. Do not use any tools.", {label: 'bravo', model: 'haiku', phase: 'Scan'}),
])
phase('Summarize')
const summary = await agent('Combine the words "' + words.filter(Boolean).join(' ') + '" into one hyphenated token. Reply with just the token. Do not use any tools.', {label: 'combine', model: 'haiku', phase: 'Summarize'})
return { words, summary }
